--1.	How many total customers are in the dataset?

SELECT COUNT(*) AS total_customers
FROM customer_churn;

--	How many customers have churned?

SELECT COUNT(*) AS churned_customers
FROM customer_churn
WHERE churn = 'Yes';

select * from customer_churn


--How many customers are still active?

select count(*) as active_customers
from customer_churn
where churn = 	'No'

--What is the overall customer churn rate?

select 
	Round(
	count(case when churn = 'Yes' then 1 end) * 100 / count(*),2) as churn_rate 
	from customer_churn

--What is the total revenue generated by all customers?


ALTER TABLE customer_churn
RENAME COLUMN "TotalCharges" TO totalcharges;

select 
		sum(totalcharges) as total_revenue
		from customer_churn
	


---What is the average monthly charge per customer?
alter table customer_churn
rename column "MonthlyCharges" to monthlycharges


alter table customer_churn
rename column "customerID" to customerid

select 
	customerid,
	AVG(monthlycharges) as monthly_charges
	from customer_churn
	group by customerID
	order by monthly_charges desc
	




--What is the average total charge each customer?

select 
 	customerid,
	avg(totalcharges) as charges
	from customer_churn
	group by customerid
	order by charges


--What is the average total charge per customer?
	SELECT 
    AVG(totalcharges) AS average_total_charge_per_customer
FROM customer_churn;



select * from customer_churn




--	What is the average customer tenure?

select 
	customerid,
	avg(tenure) as avg_tenure
	from customer_churn 
	group by customerid 
	order by avg_tenure desc
	
--What is the highest monthly charge?

select 
	max(monthlycharges) as highest_monthly_charges
	from customer_churn

--	What is the lowest monthly charge?
select 
	min(monthlycharges) as lowest_monthly_charges
	from customer_churn


--	What is the highest total charge?
select 
	max(totalcharges) as highes
	from customer_churn






--What is the lowest total charge?
select 
	min(totalcharges) as lowest
	from customer_churn
	
--	How many male and female customers are there?



select count(gender)
from customer_churn


--How many senior citizens are there?

alter table customer_churn
rename column "SeniorCitizen" to seniorcitizen

select 
COUNT(seniorcitizen)
from customer_churn
where seniorcitizen = 1




--	How many customers have partners?


alter table customer_churn
rename column 	"Partner" to partner


select 
	partner,
	count(*) as customers
	from customer_churn
	where partner = 'Yes'
	group by partner 

--	How many customers have dependents?

alter table customer_churn
rename column "Dependents" to dependents


select 
	dependents,
	count(*) as customers 
	from customer_churn
	where dependents = 	'Yes'
	group by dependents
	




--	How many customers use phone service?


alter table customer_churn
rename column "PhoneService" to phoneservice

select 
	phoneservice,
	count(*) as customers 
	from customer_churn
	where phoneservice = 	'Yes'
	group by phoneservice
	

---How many customers have multiple phone lines?


alter table customer_churn
rename column "MultipleLines" to multiplelines


select 
	multiplelines,
	count(*) as customers 
	from customer_churn
	where multiplelines = 	'Yes'
	group by multiplelines




--	How many customers use DSL, Fiber Optic, or no internet service?


select * from customer_churn


select 
	internetservice,
	Count(*) as customers
	from customer_churn
	group by internetservice 
	order by customers desc

	
--	How many customers use each contract type?

alter table customer_churn
rename column "Contract" to contract


select 
	contract,
	Count(*) as customers
	from customer_churn
	group by contract
	order by customers desc





--	How many customers use each payment method?

alter table customer_churn
rename column "PaymentMethod" to paymentmethod


select 
	paymentmethod,
	COUNT(*) as customers
	from customer_churn
	group by paymentmethod
	order by customers 
	
