--How many customers fall into each tenure group?

alter table customer_churn
rename column "TenureGroup" to tenuregroup
SELECT 
    tenuregroup,
    COUNT(*) AS customers
FROM customer_churn
GROUP BY tenuregroup
ORDER BY tenuregroup;
		

30.	What percentage of customers belong to each contract type?

select * from customer_churn

select 
	contract,
	count(*) as customers,
	Round(count(*) * 100 / sum(count(*)) over (),2) as percentage
	from customer_churn
	GROUP by contract
	order by percentage desc
	
	
